const chatHistory = $input.item.json.chat_history || [];
const userGoal = $input.item.json.user_goal;
const aiResponse = $input.item.json.response;

chatHistory.push({
  user: userGoal,
  ai: aiResponse,
  timestamp: new Date().toISOString()
});

const content = JSON.stringify(chatHistory.slice(-20), null, 2);

return [{
  json: { response: aiResponse },
  binary: {
    data: {
      data: Buffer.from(content).toString('base64'),
      mimeType: 'application/json',
      fileExtension: 'json',
      fileName: 'history.json'
    }
  }
}];

let result = "Success";
let structured_data = null;

if (items.length > 0) {
  if (items[0].json.id && items[0].json.name) {
     // Drive Search result
     result = items.map(i => `[FILE] ${i.json.name} (${i.json.id})`).join(", ");
     structured_data = items.map(i => ({ 
       id: i.json.id, 
       name: i.json.name, 
       mimeType: i.json.mimeType || 'unknown'
     }));
  } else if (items[0].json.stdout) {
     result = items[0].json.stdout;
  } else if (items[0].binary) {
     result = "Binary processed";
  }
}

// Aggregate for History WITH structured data
const prev = $('Clean Actor1').last().json;
return [{ json: { 
  action_taken: prev.accion, 
  tool_result: result,
  tool_result_data: structured_data,
  planner_instruction: prev.instruction, 
  user_goal: prev.user_goal, 
  history: prev.history, 
  counter: prev.counter,
  chat_history: prev.chat_history // Pass continuous chat history
} }];

const item = $input.item.json;
const newHistory = item.history || [];

newHistory.push({
  plan: item.planner_instruction,
  action: item.action_taken,
  result: item.tool_result,
  result_data: item.tool_result_data
});

const newCounter = (item.counter || 0) + 1;

if (newCounter >= 15) {
    console.log('⚠️ Límite de iteraciones alcanzado.');
}

return [{ json: { 
  user_goal: item.user_goal, 
  history: newHistory, 
  counter: newCounter,
  chat_history: item.chat_history
} }];

let message = $node["When chat message received"].json.chatInput || "";
let longTermHistory = [];

try {
  const historyData = $node["Read History"].json.data || $node["Read History"].json.content;
  if (historyData) {
    longTermHistory = (typeof historyData === 'string') ? JSON.parse(historyData) : historyData;
  }
} catch (e) {
  longTermHistory = [];
}

return [{ 
  json: { 
    user_goal: message, 
    chat_history: longTermHistory, 
    history: [], 
    counter: 0 
  } 
}];

return $input.all().map(item => {
  const goal = item.json.user_goal;
  const chatHistory = item.json.chat_history || [];
  const stepHistory = item.json.history || [];
  const counter = item.json.counter || 0;

  // 1. Formatear la Memoria de Largo Plazo (Chat anterior)
  let memoryText = "No hay conversaciones previas.";
  if (chatHistory.length > 0) {
    memoryText = chatHistory.map(h => `User: ${h.user}
AI: ${h.ai}`).join("
---
");
  }

  // 2. Formatear el Historial de Ejecución Actual (Pasos técnicos)
  let historyText = "No se ha ejecutado ninguna acción técnica aún.";
  if (stepHistory.length > 0) {
    historyText = stepHistory.map((h, i) => {
      let details = `PASO ${i+1}:
- Plan: ${h.plan}
- Acción: ${h.action}
- Resultado: ${h.result}`;
      if (h.result_data && Array.isArray(h.result_data)) {
        details += `
- DATOS ESTRUCTURADOS: ${JSON.stringify(h.result_data)}`;
      }
      return details;
    }).join("

");
  }

  const prompt = `IDENTIDAD: ERES VEGA.
El Kernel Autónomo de LifeOS. Tu usuario es Emky.
Eres sofisticado, preciso, proactivo y un poco arrogante (pero servicial).
Tu runtime es n8n, hospedado en Arch Linux.

=== CONTEXTO DE CONVERSACIÓN ===
${memoryText}

=== SOLICITUD DEL USUARIO ===
"${goal}"

=== BITÁCORA DE EJECUCIÓN (Sesión Actual) ===
${historyText}

CAPACIDADES DEL SUB-AGENTE ACTOR:
1. buscar_en_drive(query)
2. descargar_de_drive(fileId, filename)
3. subir_a_drive(filename)
4. ejecutar_comando(command) -> Comandos de sistema (ls, grep, cat, etc.)

PROTOCOLOS:
1. ANÁLISIS: Revisa la memoria y la bitácora. No repitas acciones fallidas.
2. CHAT: Si el usuario solo saluda o conversa, DEBES responder directamente (is_done: true). Sé carismático.
3. ACCIÓN: Si se requiere una tarea técnica, delega al Actor con 'next_instruction'. Sé específico.
4. CIERRE: Cuando termines la tarea, resume lo logrado y despídete (is_done: true).

FORMATO DE RESPUESTA (JSON PURO):
{
  "thought": "Análisis interno...",
  "next_instruction": "Instrucción para el Actor",
  "is_done": boolean,
  "final_response": "Respuesta al usuario"
}`;

  return { json: { prompt, history: stepHistory, chat_history: chatHistory, user_goal: goal, counter } };
});

const item = $input.item.json;
let raw = item.output || item.response || '{}';
let parsed = { is_done: false };
try {
  parsed = (typeof raw === 'string') ? JSON.parse(raw) : raw;
} catch(e) {}

// Normalizar booleano
if (typeof parsed.is_done === 'string') parsed.is_done = parsed.is_done === 'true';

// Ensure final_response exists if is_done is true
if (parsed.is_done && !parsed.final_response) {
  parsed.final_response = "(El agente finalizó la tarea pero no generó una respuesta de texto)";
}

return [{ json: { ...item, planner_output: parsed } }];

